    61→  }
    62→
    63→  // Add small padding
    64→  const padding = 5;
    65→  minX = Math.max(0, minX - padding);
    66→  minY = Math.max(0, minY - padding);
    67→  maxX = Math.min(img.width, maxX + padding);
    68→  maxY = Math.min(img.height, maxY + padding);
    69→
    70→  return {
    71→    x: minX,
    72→    y: minY,
    73→    width: maxX - minX,
    74→    height: maxY - minY,
    75→  };
    76→}
    77→
    78→export function ClothingCanvas({
