    91→  const lastPoseRef = useRef<PoseResult | null>(null);
    92→
    93→  // Preload images when items change
    94→  useEffect(() => {
    95→    // Clear cached anchors to force re-detection with new format
    96→    shoulderAnchorsRef.current.clear();
    97→    waistbandAnchorsRef.current.clear();
    98→
    99→    const newImages = new Map<string, HTMLImageElement>();
   100→    const loaded = new Set<string>();
   101→    let mounted = true;
   102→
   103→    const loadPromises = items.map((item) => {
   104→      return new Promise<void>((resolve) => {
   105→        // Reuse already loaded images
   106→        if (imagesRef.current.has(item.id)) {
   107→          const existingImg = imagesRef.current.get(item.id)!;
   108→          newImages.set(item.id, existingImg);
   109→          loaded.add(item.id);
   110→          resolve();
   111→          return;
   112→        }
   113→
   114→        // Load new image
   115→        const img = new Image();
   116→        img.crossOrigin = 'anonymous';
   117→
   118→        img.onload = async () => {
   119→          if (mounted) {
   120→            // Detect and store content bounds (crop transparent padding)
   121→            const bounds = detectImageBounds(img);
   122→            boundsRef.current.set(item.id, bounds);
   123→
   124→            // Detect anchor points based on category
   125→            if (item.category === 'tops') {
   126→              try {
   127→                console.log(`Detecting shoulder seams for ${item.id}...`);
   128→                const shoulderAnchors = detectShoulderSeams(img);
   129→                if (shoulderAnchors) {
   130→                  shoulderAnchorsRef.current.set(item.id, shoulderAnchors);
   131→                  console.log(`✓ Shoulder seams detected for ${item.id}:`, shoulderAnchors);
   132→                } else {
   133→                  console.warn(`Could not detect shoulder seams for ${item.id}, will use fallback`);
   134→                }
   135→              } catch (error) {
   136→                console.error(`Shoulder seam detection failed for ${item.id}:`, error);
   137→                // Continue without anchor points (will use fallback)
   138→              }
   139→            } else if (item.category === 'bottoms') {
   140→              try {
   141→                console.log(`Detecting waistband for ${item.id}...`);
   142→                const waistbandAnchors = detectWaistband(img);
   143→                if (waistbandAnchors) {
   144→                  waistbandAnchorsRef.current.set(item.id, waistbandAnchors);
   145→                  console.log(`✓ Waistband detected for ${item.id}:`, waistbandAnchors);
   146→                } else {
   147→                  console.warn(`Could not detect waistband for ${item.id}, will use fallback`);
   148→                }
   149→              } catch (error) {
