   176→      }
   177→    });
   178→
   179→    return () => {
   180→      mounted = false;
   181→    };
   182→  }, [items, onImageError]);
   183→
   184→  // Render clothing overlays
   185→  const render = useCallback(() => {
   186→    const canvas = canvasRef.current;
   187→    if (!canvas) return;
