   266→          shirtRightShoulder.y - shirtLeftShoulder.y
   267→        );
   268→        const shirtTorsoHeight = Math.hypot(
   269→          shirtLeftHem.x - shirtLeftShoulder.x,
   270→          shirtLeftHem.y - shirtLeftShoulder.y
   271→        );
   272→
   273→        // Calculate body measurements
