   329→        // Image top-left → Body left hip
   330→        // Image top-right → Body right hip
   331→        // Image bottom-left → Body left ankle
   332→        // Image bottom-right → Body right ankle
   333→
   334→        // Image corner pixels (in image coordinates)
   335→        const imgTopLeft = {
   336→          x: waistbandAnchors.topLeft.x * img.width,
   337→          y: waistbandAnchors.topLeft.y * img.height,
   338→        };
   339→        const imgTopRight = {
   340→          x: waistbandAnchors.topRight.x * img.width,
   341→          y: waistbandAnchors.topRight.y * img.height,
   342→        };
   343→        const imgBottomLeft = {
   344→          x: waistbandAnchors.bottomLeft.x * img.width,
   345→          y: waistbandAnchors.bottomLeft.y * img.height,
   346→        };
   347→        const imgBottomRight = {
   348→          x: waistbandAnchors.bottomRight.x * img.width,
   349→          y: waistbandAnchors.bottomRight.y * img.height,
