   380→        const renderWidth = srcWidth * scale;
   381→        const renderHeight = srcHeight * scale;
   382→
   383→        // Position at body quad center
   384→        const bodyCenterX = (bodyLeftHip.x + bodyRightHip.x + bodyLeftAnkle.x + bodyRightAnkle.x) / 4;
   385→        const bodyCenterY = (bodyLeftHip.y + bodyRightHip.y + bodyLeftAnkle.y + bodyRightAnkle.y) / 4;
   386→
   387→        // Rotation from body hip line
   388→        const rotation = Math.atan2(
   389→          bodyRightHip.y - bodyLeftHip.y,
   390→          bodyRightHip.x - bodyLeftHip.x
   391→        ) + Math.PI;
   392→
   393→        ctx.save();
   394→        ctx.translate(bodyCenterX, bodyCenterY);
   395→        ctx.rotate(rotation);
   396→        ctx.scale(-1, 1); // Flip horizontally
   397→        ctx.globalAlpha = 1.0;
   398→
   399→        // Draw the detected region
   400→        ctx.drawImage(
   401→          img,
   402→          srcX, srcY, srcWidth, srcHeight,
   403→          -renderWidth / 2, -renderHeight / 2, renderWidth, renderHeight
   404→        );
   405→
   406→        ctx.restore();
   407→
   408→        console.log(`[Render] 4-corner mapping | TL:(${imgTopLeft.x.toFixed(0)},${imgTopLeft.y.toFixed(0)}) → Hip, BR:(${imgBottomRight.x.toFixed(0)},${imgBottomRight.y.toFixed(0)}) → Ankle`);
   409→      } else {
   410→        // Fallback: use standard quad rendering without anchor points
   411→        const bounds = boundsRef.current.get(item.id) || {
   412→          x: 0,
   413→          y: 0,
   414→          width: img.width,
   415→          height: img.height,
   416→        };
   417→
   418→        const topWidth = Math.hypot(
